import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

// ─────────────────────────────────────────────────────────────
// SATURN RING — padat seperti di referensi, putih bersinar
// Satu ring tebal, bukan beberapa layer tipis
// ─────────────────────────────────────────────────────────────
function SaturnRingBand({ innerRadius, outerRadius, particleCount, tiltX, color, speed }) {
  const groupRef = useRef();

  const geometry = useMemo(() => {
    const geo = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    const alphas = new Float32Array(particleCount);

    for (let i = 0; i < particleCount; i++) {
      const angle = Math.random() * Math.PI * 2;
      // bias toward middle of band for denser look
      const t = Math.pow(Math.random(), 0.5);
      const r = innerRadius + t * (outerRadius - innerRadius);
      // very thin disc — almost flat
      const y = (Math.random() - 0.5) * 0.15;

      positions[i * 3 + 0] = Math.cos(angle) * r;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = Math.sin(angle) * r;

      // vary opacity so inner part looks denser
      alphas[i] = 0.5 + Math.random() * 0.5;
    }

    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    return geo;
  }, [innerRadius, outerRadius, particleCount]);

  useFrame(() => {
    if (groupRef.current) {
      groupRef.current.rotation.y += speed;
    }
  });

  return (
    <group ref={groupRef} rotation={[tiltX, 0, 0]}>
      <points geometry={geometry}>
        <pointsMaterial
          color={color}
          size={0.22}
          sizeAttenuation
          transparent={false}
          opacity={1}
          depthWrite={false}
        />
      </points>
    </group>
  );
}

// ─────────────────────────────────────────────────────────────
// FOTO ORBITAL — berputar mengitari hati di atas ring
// ─────────────────────────────────────────────────────────────
const PHOTO_RINGS = [
  { count: 10, radius: 6.5,  tiltX: 0.22, speed: 0.20, yLift: 0.5 },
  { count: 12, radius: 9.5,  tiltX: 0.22, speed: 0.14, yLift: 0.5 },
  { count: 14, radius: 12.8, tiltX: 0.22, speed: 0.09, yLift: 0.5 },
  { count: 14, radius: 16.5, tiltX: 0.22, speed: 0.06, yLift: 0.5 },
];

function buildOrbitParams(count) {
  const params = [];
  let idx = 0;
  for (let r = 0; r < PHOTO_RINGS.length && idx < count; r++) {
    const ring = PHOTO_RINGS[r];
    const n = Math.min(ring.count, count - idx);
    for (let i = 0; i < n; i++) {
      params.push({
        angleOffset: (i / ring.count) * Math.PI * 2,
        radius: ring.radius,
        tiltX: ring.tiltX,
        speed: ring.speed,
        yLift: ring.yLift,
        floatSeed: idx * 0.53,
      });
      idx++;
    }
  }
  while (idx < count) {
    params.push({
      angleOffset: ((idx % 12) / 12) * Math.PI * 2,
      radius: 20.5,
      tiltX: 0.22,
      speed: 0.04,
      yLift: 0.5,
      floatSeed: idx * 0.53,
    });
    idx++;
  }
  return params;
}

function useOrbit(orbit, meshRef, materialRef) {
  useFrame(({ clock }) => {
    if (!meshRef.current) return;
    const t = clock.elapsedTime;
    const angle = orbit.angleOffset + t * orbit.speed;

    const cosA = Math.cos(angle);
    const sinA = Math.sin(angle);
    const cosT = Math.cos(orbit.tiltX);
    const sinT = Math.sin(orbit.tiltX);

    // flat ring position, then tilt
    const flatX = cosA * orbit.radius;
    const flatZ = sinA * orbit.radius;
    const tiltedY = flatZ * sinT;
    const tiltedZ = flatZ * cosT;

    meshRef.current.position.set(
      flatX,
      tiltedY + orbit.yLift + Math.sin(t * 0.55 + orbit.floatSeed) * 0.12,
      tiltedZ
    );

    // face outward
    meshRef.current.rotation.y = -angle + Math.PI / 2;
    meshRef.current.rotation.x = orbit.tiltX * 0.5;

    // fade in/out every 2 orbits
    if (materialRef?.current) {
      const fade = Math.sin(angle * 0.5);
      const target = fade < -0.6 ? Math.max(0, 1 - (Math.abs(fade) - 0.6) / 0.4) : 1;
      materialRef.current.opacity = THREE.MathUtils.lerp(materialRef.current.opacity, target, 0.08);
    }
  });
}

function RealPhotoCard({ url, orbit, onClick }) {
  const meshRef = useRef();
  const materialRef = useRef();
  const [hovered, setHovered] = useState(false);
  const texture = useTexture(url);
  useOrbit(orbit, meshRef, materialRef);
  return (
    <mesh ref={meshRef} scale={hovered ? 1.3 : 1}
      onClick={e => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}>
      <planeGeometry args={[1.6, 1.15]} />
      <meshStandardMaterial ref={materialRef} map={texture} side={THREE.DoubleSide} transparent opacity={1} />
    </mesh>
  );
}

function ColorCard({ color, orbit, index, onClick }) {
  const meshRef = useRef();
  const materialRef = useRef();
  const [hovered, setHovered] = useState(false);
  const c = useMemo(() => new THREE.Color(color), [color]);
  useOrbit(orbit, meshRef, materialRef);
  return (
    <mesh ref={meshRef} scale={hovered ? 1.3 : 1}
      onClick={e => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}>
      <planeGeometry args={[1.6, 1.15]} />
      <meshStandardMaterial ref={materialRef} color={c} emissive={c} emissiveIntensity={0.5}
        side={THREE.DoubleSide} transparent opacity={1} />
    </mesh>
  );
}

function PhotoCard({ photo, orbit, index, onClick }) {
  if (photo.startsWith('__color__')) {
    return <ColorCard color={photo.replace('__color__', '')} orbit={orbit} index={index} onClick={onClick} />;
  }
  return <RealPhotoCard url={photo} orbit={orbit} onClick={onClick} />;
}

// ─────────────────────────────────────────────────────────────
// EXPORT UTAMA
// ─────────────────────────────────────────────────────────────
export default function PhotoStars({ photos, onPhotoClick }) {
  const orbitParams = useMemo(() => buildOrbitParams(photos.length), [photos.length]);

  // Cincin partikel — satu massa padat putih bersinar seperti di referensi
  // tiltX sama dengan foto agar partikel dan foto sejajar
  const TILT = 0.22;
  const rings = [
    { inner: 4.2,  outer: 7.8,  count: 8000,  color: '#ffffff', speed: 0.0012 },
    { inner: 7.4,  outer: 11.0, count: 10000, color: '#ffe8f5', speed: 0.0010 },
    { inner: 10.5, outer: 14.5, count: 11000, color: '#e8f0ff', speed: 0.0008 },
    { inner: 14.0, outer: 18.5, count: 11000, color: '#fff5e8', speed: 0.0006 },
  ];

  return (
    <group>
      {/* SATURN PARTICLE RINGS */}
      {rings.map((r, i) => (
        <SaturnRingBand
          key={i}
          innerRadius={r.inner}
          outerRadius={r.outer}
          particleCount={r.count}
          tiltX={TILT}
          color={r.color}
          speed={r.speed}
        />
      ))}

      {/* FOTO DI ATAS RING */}
      {photos.map((photo, i) => (
        <PhotoCard
          key={i}
          photo={photo}
          orbit={orbitParams[i]}
          index={i}
          onClick={() => onPhotoClick(photo, i)}
        />
      ))}
    </group>
  );
}
